void bfs(TreeNode *root) {
    if (root == NULL) return;
    TreeNode *queue[100];
    int front = 0, back = 0;
    queue[back++] = root;
    while (front < back) {
        TreeNode *node = queue[front++];
        printf("%d ", node->val);
        if (node->left)  queue[back++] = node->left;
        if (node->right) queue[back++] = node->right;
    }
}

